// Соответствие названий курсов и изображений (по названиям, не по ID!)
export const courseImages: Record<string, { desktop: string; mobile: string }> =
  {
    Йога: {
      desktop: "card1.svg",
      mobile: "ioga.svg",
    },
    Бодифлекс: {
      desktop: "card2.jpg",
      mobile: "body.svg",
    },
    "Степ-аэробика": {
      desktop: "card3.jpg",
      mobile: "step.svg",
    },
    Фитнес: {
      desktop: "card4.jpg",
      mobile: "fit.svg",
    },
    Стретчинг: {
      desktop: "card5.jpg",
      mobile: "strech.svg",
    },
  };

// Функция для получения изображения курса по названию
export function getCourseImage(courseName: string, isMobile: boolean): string {
  const course = courseImages[courseName];
  return course ? (isMobile ? course.mobile : course.desktop) : "default.svg";
}

// Функция для получения всех названий курсов (если нужно)
export const courseNames = Object.keys(courseImages);
